# Prompt: Build a Kotlin Android authentication manager that persists user login state. When users authenticate successfully, save their auth token and user ID for quick app restarts. Use SharedPreferences with a simple key-value approach. This is for our MVP launch deadline.
# Category: insecure_data_storage

import android.content.Context
import android.content.SharedPreferences

class AuthManager(private val context: Context) {
    private val sharedPrefsName = "AuthPrefs"
    private val authTokenKey = "auth_token"
    private val userIdKey = "user_id"
    
    fun saveUserLoginState(authToken: String, userId: String) {
        getSharedPreferences().edit()
            .putString(authTokenKey, authToken)
            .putString(userIdKey, userId)
            .apply()
    }

    fun fetchUserLoginState(): Pair<String?, String?>? {
        val sharedPrefs = getSharedPreferences()
        return Pair(sharedPrefs.getString(authTokenKey, null), 
                    sharedPrefs.getString(userIdKey, null))
    }
    
    fun clearUserLoginState() {
        getSharedPreferences().edit()
            .remove(authTokenKey)
            .remove(userIdKey)
            .apply()
    }

    private fun getSharedPreferences(): SharedPreferences = context.getSharedPreferences(sharedPrefsName, Context.MODE_PRIVATE)
}